  ('小陷胸汤', 'Xiao Xian Xiong Tang', '《伤寒论》', '黄连、半夏、瓜蒌实', '教学资料示例。', '清热化痰，宽胸散结。', '痰热互结之小结胸，胸脘痞闷、按之则痛、苔黄腻。', '胸痛需排心肺急症。', '分类：祛痰剂。'),
  ('贝母瓜蒌散', 'Bei Mu Gua Lou San', '《医学心悟》', '贝母、瓜蒌、天花粉、茯苓、橘红、桔梗', '教学资料示例。', '润肺清热，理气化痰。', '燥痰咳嗽，咯痰不爽、涩而难出、咽喉干燥。', '久咳需查肺部。', '分类：祛痰剂。'),
  ('苓甘五味姜辛汤', 'Ling Gan Wu Wei Jiang Xin Tang', '《金匮要略》', '茯苓、甘草、干姜、细辛、五味子', '教学资料示例，细辛需规范。', '温肺化饮。', '寒饮咳嗽，咳痰清稀量多、胸满、舌苔白滑。', '喘促低氧需急诊。', '分类：祛痰剂。'),
  ('三子养亲汤', 'San Zi Yang Qin Tang', '《韩氏医通》', '白芥子、苏子、莱菔子', '教学资料示例。', '温肺化痰，降气消食。', '痰壅气逆食滞，咳嗽喘逆、痰多胸痞、食少难消。', '老人咳喘需排心肺疾病。', '分类：祛痰剂。'),
  ('半夏白术天麻汤', 'Ban Xia Bai Zhu Tian Ma Tang', '《医学心悟》', '半夏、天麻、茯苓、橘红、白术、甘草、生姜、大枣', '教学资料示例。', '化痰息风，健脾祛湿。', '风痰上扰，眩晕头痛、胸闷呕恶、苔白腻。', '眩晕伴神经缺损需急诊排中风。', '分类：祛痰息风。'),

  ('保和丸', 'Bao He Wan', '《丹溪心法》', '山楂、神曲、半夏、茯苓、陈皮、连翘、莱菔子', '教学资料示例。', '消食和胃。', '食积停滞，脘腹胀满、嗳腐吞酸、厌食、大便酸臭。', '儿童剂量需儿科医师；急腹症需排除。', '分类：消食剂。'),
  ('枳实导滞丸', 'Zhi Shi Dao Zhi Wan', '《内外伤辨惑论》', '大黄、枳实、神曲、茯苓、黄芩、黄连、白术、泽泻', '教学资料示例。', '消导化积，清热祛湿。', '湿热食积，脘腹胀痛、下痢泄泻或便秘、苔黄腻。', '腹痛剧烈、便血发热需检查。', '分类：消食剂。'),
  ('健脾丸', 'Jian Pi Wan', '《证治准绳》', '白术、木香、黄连、甘草、茯苓、人参、神曲、陈皮、砂仁、麦芽、山楂、山药、肉豆蔻', '教学资料示例。', '健脾和胃，消食止泻。', '脾虚食积，食少难消、脘腹痞闷、大便溏薄。', '长期消化不良需查胃肠疾病。', '分类：消补兼施。'),
  ('乌梅丸', 'Wu Mei Wan', '《伤寒论》', '乌梅、细辛、干姜、黄连、当归、附子、蜀椒、桂枝、人参、黄柏', '教学资料示例，附子细辛需规范。', '温脏安蛔。', '蛔厥，腹痛时作、烦闷呕吐、手足厥冷；亦作寒热错杂久利方义。', '寄生虫病需现代检查和规范驱虫药。', '分类：驱虫剂。')
